import React, { useState, useEffect } from "react";
import RouteForm from "./components/RouteForm";
import TripForm from "./components/TripForm";
import RouteTable from "./components/RouteTable";
import StationForm from "./components/StationForm";
import TrainForm from "./components/TrainForm";

function App() {
  const [routes, setRoutes] = useState([]);
  const [trips, setTrips] = useState([]);
  const [stations, setStations] = useState([]);
  const [trains, setTrains] = useState([]);

  // Загружаем данные с сервера при старте
  useEffect(() => {
    fetch("http://localhost:5050/routes").then(r => r.json()).then(setRoutes).catch(console.error);
    fetch("http://localhost:5050/trips").then(r => r.json()).then(setTrips).catch(console.error);
    fetch("http://localhost:5050/stations").then(r => r.json()).then(setStations).catch(console.error);
    fetch("http://localhost:5050/trains").then(r => r.json()).then(setTrains).catch(console.error);
  }, []);

  // Получить номер поезда по ID
  const getTrainNumber = (trainId) => {
    const train = trains.find(t => t.id === trainId);
    return train ? train.number : trainId;
  };

  return (
    <div style={{ padding: "20px", fontFamily: "Arial" }}>
      <h1>Прототип ПК/ПАК — маршруты, поезда, станции и рейсы</h1>

      <div style={{ marginBottom: "20px" }}>
        <StationForm onNewStation={(station) => setStations(prev => [...prev, station])} />
      </div>

      <div style={{ marginBottom: "20px" }}>
        <TrainForm onNewTrain={(train) => setTrains(prev => [...prev, train])} />
      </div>

      <div style={{ marginBottom: "20px" }}>
        <RouteForm 
          stations={stations} 
          onNewRoute={(route) => setRoutes(prev => [...prev, route])} 
        />
      </div>

      <div style={{ marginBottom: "20px" }}>
        <TripForm 
          routes={routes} 
          trains={trains} 
          onNewTrip={(trip) => setTrips(prev => [...prev, trip])} 
        />
      </div>

      <div>
        <RouteTable 
          routes={routes} 
          trips={trips} 
          getTrainNumber={getTrainNumber} 
        />
      </div>
    </div>
  );
}

export default App;
